/* @diffgazer/ui Theme - Shared base (utility classes, animations, @theme mappings) */

/*
 * Cascade layer order. Declared before any other @layer rule so consumers can
 * predict override resolution without depending on bundler source order.
 * Lower layers in the list lose to higher layers: theme tokens < base styles
 * < component styles < utilities. Tailwind v4 emits its own utilities and
 * components into matching layer names.
 */
@layer theme, base, components, utilities;

.ui-base {
  font-family: var(--base-font-mono);
  background-color: var(--background);
  color: var(--foreground);
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-thin::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

.scrollbar-thin::-webkit-scrollbar-track {
  background: transparent;
}

.scrollbar-thin::-webkit-scrollbar-thumb {
  background: transparent;
  border-radius: 2px;
  transition: background 0.15s ease;
}

.scrollbar-thin:hover::-webkit-scrollbar-thumb,
.scrollbar-thin:focus-within::-webkit-scrollbar-thumb {
  background: var(--border);
}

.scrollbar-thin::-webkit-scrollbar-thumb:hover {
  background: var(--foreground);
}

.scrollbar-thin {
  scrollbar-width: thin;
  scrollbar-color: transparent transparent;
  transition: scrollbar-color 0.15s ease;
}

.scrollbar-thin:hover,
.scrollbar-thin:focus-within {
  scrollbar-color: var(--border) transparent;
}

@keyframes ui-blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0;
  }
}

.cursor-blink {
  animation: ui-blink 1s step-end infinite;
}

@keyframes ui-progress-indeterminate {
  0% {
    width: 40%;
    transform: translateX(-100%);
  }
  50% {
    width: 40%;
    transform: translateX(150%);
  }
  100% {
    width: 40%;
    transform: translateX(-100%);
  }
}

.progress-indeterminate {
  animation: ui-progress-indeterminate 1.5s ease-in-out infinite;
}

@media (prefers-reduced-motion: reduce) {
  .cursor-blink {
    animation: none;
  }
  .progress-indeterminate {
    animation: none;
    width: 40%;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb,
  .scrollbar-thin {
    transition: none;
  }
}

/*
 * scrollbar-gutter: stable on global <html> avoids horizontal layout shift
 * when scrollbars toggle. Safari did not ship scrollbar-gutter until 18.2;
 * @supports keeps Safari 16.4-18.1 from inheriting a declaration it ignores
 * silently. Older Safari simply does not reserve the gutter (cosmetic only).
 */
@supports (scrollbar-gutter: stable) {
  html {
    scrollbar-gutter: stable;
  }
}

@custom-variant dark (&:where(.dark, .dark *, [data-theme="dark"], [data-theme="dark"] *));

/*
 * Reference mappings live in `@theme inline` so each utility resolves its
 * semantic var() at the styled element instead of substituting it at :root.
 * That lets a `data-theme` (or token override) on ANY subtree re-theme the
 * token utilities below — see theme/dark-mode.mdx.
 */
@theme inline {
  --color-base-bg: var(--base-bg);
  --color-base-fg: var(--base-fg);
  --color-base-dim: var(--base-dim);
  --color-base-border: var(--base-border);
  --color-base-highlight: var(--base-highlight);
  --color-base-highlight-foreground: var(--base-highlight-foreground);
  --color-base-input-bg: var(--base-input-bg);
  --color-base-muted: var(--base-muted);
  --color-base-selection: var(--base-selection);
  --color-base-info: var(--base-info);
  --color-base-accent: var(--base-accent);
  --color-base-success: var(--base-success);
  --color-base-danger: var(--base-danger);
  --color-base-warning: var(--base-warning);
  --color-base-surface-1: var(--surface-1);

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
  --color-info: var(--info);
  --color-info-foreground: var(--info-foreground);
  --color-error: var(--error);
  --color-error-foreground: var(--error-foreground);
  --color-success-subtle: var(--success-subtle);
  --color-success-text: var(--success-text);
  --color-success-border: var(--success-border);
  --color-success-strong: var(--success-strong);
  --color-success-strong-foreground: var(--success-strong-foreground);
  --color-warning-subtle: var(--warning-subtle);
  --color-warning-text: var(--warning-text);
  --color-warning-border: var(--warning-border);
  --color-warning-strong: var(--warning-strong);
  --color-warning-strong-foreground: var(--warning-strong-foreground);
  --color-error-subtle: var(--error-subtle);
  --color-error-text: var(--error-text);
  --color-error-border: var(--error-border);
  --color-error-strong: var(--error-strong);
  --color-error-strong-foreground: var(--error-strong-foreground);
  --color-info-subtle: var(--info-subtle);
  --color-info-text: var(--info-text);
  --color-info-border: var(--info-border);
  --color-info-strong: var(--info-strong);
  --color-info-strong-foreground: var(--info-strong-foreground);
  --color-neutral-subtle: var(--neutral-subtle);
  --color-neutral-border: var(--neutral-border);
  --color-neutral-text: var(--neutral-text);
  --color-neutral-strong: var(--neutral-strong);
  --color-neutral-strong-foreground: var(--neutral-strong-foreground);
  --color-action: var(--action);
  --color-action-foreground: var(--action-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  --radius-lg: var(--radius);
  --radius-md: calc(var(--radius) - 2px);
  --radius-sm: max(calc(var(--radius) - 4px), 1px);
}

@theme {
  --font-sans: "Inter", sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;

  --text-2xs: 0.625rem;
  --text-3xs: 0.5625rem;

  /*
   * Z-index scale for overlay surfaces. Native <dialog>.showModal() and the
   * HTML Popover API paint in the browser top-layer, which sits above every
   * z-index value — see apps/docs/content/docs/ui/theme/index.mdx.
   */
  --z-base: 1;
  --z-dropdown: 100;
  --z-overlay: 200;
  --z-popover: 300;
  --z-toast: 400;

  --animate-fade-in: fade-in 0.2s ease-out;
  --animate-fade-out: fade-out 0.15s ease-in forwards;
  --animate-slide-in: slide-in 0.2s ease-out;
  --animate-slide-out: slide-out 0.15s ease-in forwards;
  --animate-slide-in-right: slide-in-right 0.2s ease-out;
  --animate-slide-out-right: slide-out-right 0.15s ease-in forwards;
  --animate-slide-in-left: slide-in-left 0.2s ease-out;
  --animate-slide-out-left: slide-out-left 0.15s ease-in forwards;
  --animate-slide-in-top: slide-in-top 0.2s ease-out;
  --animate-slide-out-top: slide-out-top 0.15s ease-in forwards;
  --animate-slide-in-bottom: slide-in-bottom 0.2s ease-out;
  --animate-slide-out-bottom: slide-out-bottom 0.15s ease-in forwards;

  /*
   * Floating-surface animation contract (Popover, Select, future Menu/Combobox via FloatingPanel).
   * Each `--ui-content-enter-from-<side>` / `--ui-content-exit-to-<side>` token holds the full
   * `animation` shorthand for that direction, so `.ui-floating-panel[data-side="<side>"]` maps
   * directly. All 8 directional tokens are kept (vs. collapsed to a single pair) so consumers
   * can override per side with transform-based keyframes; `--ui-content-transform-origin` is
   * set automatically by FloatingPanel for those overrides. Reduced motion overrides below.
   */
  --ui-content-enter-duration: 60ms;
  --ui-content-exit-duration: 40ms;
  --ui-content-enter-from-top: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-enter-from-bottom: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-enter-from-left: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-enter-from-right: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-exit-to-top: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  --ui-content-exit-to-bottom: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  --ui-content-exit-to-left: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  --ui-content-exit-to-right: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;

  @keyframes fade-in {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  @keyframes fade-out {
    from {
      opacity: 1;
    }
    to {
      opacity: 0;
    }
  }
  @keyframes slide-in {
    from {
      transform: translateY(10px);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }
  @keyframes slide-out {
    from {
      transform: translateY(0);
      opacity: 1;
    }
    to {
      transform: translateY(8px);
      opacity: 0;
    }
  }
  @keyframes slide-in-right {
    from {
      transform: translateX(100%);
      opacity: 0;
    }
    to {
      transform: translateX(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-right {
    from {
      transform: translateX(0);
      opacity: 1;
    }
    to {
      transform: translateX(100%);
      opacity: 0;
    }
  }
  @keyframes slide-in-left {
    from {
      transform: translateX(-100%);
      opacity: 0;
    }
    to {
      transform: translateX(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-left {
    from {
      transform: translateX(0);
      opacity: 1;
    }
    to {
      transform: translateX(-100%);
      opacity: 0;
    }
  }
  @keyframes slide-in-top {
    from {
      transform: translateY(-100%);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-top {
    from {
      transform: translateY(0);
      opacity: 1;
    }
    to {
      transform: translateY(-100%);
      opacity: 0;
    }
  }
  @keyframes slide-in-bottom {
    from {
      transform: translateY(100%);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-bottom {
    from {
      transform: translateY(0);
      opacity: 1;
    }
    to {
      transform: translateY(100%);
      opacity: 0;
    }
  }

}

/*
 * Floating-surface keyframes. Tailwind v4 keeps @keyframes nested in @theme only
 * when their paired `--animate-*` variable is used; these are paired with
 * `--ui-content-*` (not `--animate-*`), so they're declared at top level to
 * ensure emission.
 */
@keyframes ui-content-enter-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}
@keyframes ui-content-exit-fade {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

/*
 * Public CSS variables for consumers to override per-instance:
 *   --ui-floating-z         — z-index layer (default: var(--z-popover))
 *   --ui-content-enter-from-{top|bottom|left|right}   — enter animation shorthand
 *   --ui-content-exit-to-{top|bottom|left|right}      — exit animation shorthand
 *   --ui-content-enter-duration, --ui-content-exit-duration
 *   --ui-content-transform-origin  — set automatically; usable from transform-based overrides
 *   --ui-floating-trigger-width    — set when matchTriggerWidth (Select etc.)
 *
 * Rules live in @layer components so consumer @layer utilities (e.g. animate-none)
 * can override them without specificity escalation. The `[data-positioned]` gate
 * prevents the first-frame race where the animation would otherwise start before
 * `useFloatingPosition` has measured.
 */
@layer components {
  .ui-floating-panel {
    transform-origin: var(--ui-content-transform-origin, center);
    z-index: var(--ui-floating-z, var(--z-popover));
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="bottom"] {
    animation: var(--ui-content-enter-from-top);
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="top"] {
    animation: var(--ui-content-enter-from-bottom);
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="right"] {
    animation: var(--ui-content-enter-from-left);
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="left"] {
    animation: var(--ui-content-enter-from-right);
  }
  .ui-floating-panel[data-state="closed"] {
    pointer-events: none;
  }
  .ui-floating-panel[data-state="closed"][data-side="bottom"] {
    animation: var(--ui-content-exit-to-top);
  }
  .ui-floating-panel[data-state="closed"][data-side="top"] {
    animation: var(--ui-content-exit-to-bottom);
  }
  .ui-floating-panel[data-state="closed"][data-side="right"] {
    animation: var(--ui-content-exit-to-left);
  }
  .ui-floating-panel[data-state="closed"][data-side="left"] {
    animation: var(--ui-content-exit-to-right);
  }
}

/*
 * Tailwind v4 compiles `animate-<key>` to `animation: var(--animate-<key>)`.
 * Overriding each animation token to `none` under prefers-reduced-motion
 * neutralizes every token consumer (Popover, Select, Toast, future surfaces)
 * without retrofitting `motion-safe:` everywhere. Components that use the
 * arbitrary `animate-[...]` form or CSS-only animations handle reduced motion
 * locally.
 */
@media (prefers-reduced-motion: reduce) {
  :root {
    --animate-fade-in: none;
    --animate-fade-out: none;
    --animate-slide-in: none;
    --animate-slide-out: none;
    --animate-slide-in-right: none;
    --animate-slide-out-right: none;
    --animate-slide-in-left: none;
    --animate-slide-out-left: none;
    --animate-slide-in-top: none;
    --animate-slide-out-top: none;
    --animate-slide-in-bottom: none;
    --animate-slide-out-bottom: none;
    --ui-content-enter-from-top: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-enter-from-bottom: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-enter-from-left: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-enter-from-right: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-exit-to-top: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
    --ui-content-exit-to-bottom: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
    --ui-content-exit-to-left: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
    --ui-content-exit-to-right: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  }
}

/* Windows High Contrast Mode */
@media (forced-colors: active) {
  :root {
    --border: CanvasText;
    --ring: Highlight;
    --foreground: CanvasText;
    --background: Canvas;
    --muted-foreground: CanvasText;
  }
}

/* Increased contrast preference */
@media (prefers-contrast: more) {
  :root,
  [data-theme="dark"] {
    --base-dim: #b3b3b3;
    --base-border: #777777;
    --base-muted: #999999;
    --base-accent: #b3b3b3;
  }
  [data-theme="light"] {
    --base-dim: #4a4a4a;
    --base-border: #6e6e6e;
    --base-muted: #555555;
  }
}

/* Shiki dual-theme variable resolution */
.shiki,
.shiki span {
  color: var(--shiki-light);
  background-color: var(--shiki-light-bg);
}

[data-theme="light"] .shiki,
[data-theme="light"] .shiki span {
  color: var(--shiki-light);
  background-color: var(--shiki-light-bg);
}

[data-theme="dark"] .shiki,
[data-theme="dark"] .shiki span {
  color: var(--shiki-dark);
  background-color: var(--shiki-dark-bg);
}

/* @diffgazer/ui Theme - Diffgazer (Minimal Monochrome) */

@import "./theme-base.css";

:root,
[data-theme="dark"] {
  /* Primitive base colors - Diffgazer Theme */
  --base-bg: #0a0a0a;
  --base-fg: #e5e5e5;
  --base-dim: #9c9c9c;
  --base-border: #606060;
  --base-highlight: #ffffff;
  --base-highlight-foreground: #000000;
  --base-input-bg: #0a0a0a;
  --base-muted: #808080; /* ≥4.5:1 on #0a0a0a (was #787878, 4.48:1) */
  --base-selection: #333333;

  /* Accent colors - simplified for minimal theme */
  --base-info: #ccccff; /* light for links */
  --base-accent: #808080; /* ≥4.5:1 on #0a0a0a (was #787878, 4.48:1) */
  --base-success: #e5e5e5; /* white for success in minimal */
  --base-danger: #ff7b72; /* keep for error */
  --base-warning: #d29922; /* keep for warning */

  /* Code syntax palette (shared by Fumadocs + generated snippets) */
  --code-comment: var(--base-dim);
  --code-string: var(--base-accent);
  --code-number: var(--base-accent);
  --code-keyword: var(--base-info);
  --code-function: var(--base-success);
  --code-tag: var(--base-success);
  --code-attr: var(--base-info);
  --code-parameter: var(--base-warning);
  --code-operator: var(--base-danger);
  --code-variable: var(--base-fg);
  --code-type: var(--base-info);

  --base-font-mono:
    "JetBrains Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono",
    monospace;

  /* Semantic mappings */
  --background: var(--base-bg);
  --foreground: var(--base-fg);
  --primary: var(--base-fg);
  --primary-foreground: var(--base-bg);
  --secondary: var(--base-selection);
  --secondary-foreground: var(--base-fg);
  --muted: var(--base-muted);
  --muted-foreground: var(--base-dim);
  --border: var(--base-border);
  --input: var(--base-selection);
  --accent: var(--base-highlight);
  --accent-foreground: var(--base-highlight-foreground);
  --card: var(--base-selection);
  --card-foreground: var(--base-fg);
  --popover: var(--base-selection);
  --popover-foreground: var(--base-fg);
  --ring: var(--base-fg);
  --success: var(--base-success);
  --success-foreground: var(--base-bg);
  --warning: var(--base-warning);
  --warning-foreground: var(--base-bg);
  --info: var(--base-info);
  --info-foreground: var(--base-bg);
  --error: var(--base-danger);
  --error-foreground: var(--base-bg);

  /*
   * Subtle tone backgrounds derive from their primitive via color-mix so a
   * single primitive override re-tints every subtle surface (Badge/Callout).
   * Percentages preserve the historical alpha; neutral anchors to --base-border.
   */
  --success-subtle: color-mix(in oklab, var(--base-success) 10%, transparent);
  --success-text: var(--base-success);
  --success-border: var(--base-success);
  --success-strong: var(--base-success);
  --success-strong-foreground: var(--base-bg);

  --warning-subtle: color-mix(in oklab, var(--base-warning) 5%, transparent);
  --warning-text: var(--base-warning);
  --warning-border: var(--base-warning);
  --warning-strong: var(--base-warning);
  --warning-strong-foreground: var(--base-bg);

  --error-subtle: color-mix(in oklab, var(--base-danger) 10%, transparent);
  --error-text: var(--base-danger);
  --error-border: var(--base-danger);
  --error-strong: var(--base-danger);
  --error-strong-foreground: var(--base-bg);

  --info-subtle: color-mix(in oklab, var(--base-info) 10%, transparent);
  --info-text: var(--base-info);
  --info-border: var(--base-info);
  --info-strong: var(--base-info);
  --info-strong-foreground: var(--base-bg);

  --neutral-subtle: color-mix(in oklab, var(--base-border) 10%, transparent);
  --neutral-border: var(--base-border);
  --neutral-text: var(--base-muted);
  --neutral-strong: var(--base-muted);
  --neutral-strong-foreground: var(--base-bg);

  --action: var(--base-highlight);
  --action-foreground: var(--base-highlight-foreground);

  /* Shared scrim for modal backdrops (same value across themes). */
  --scrim: rgb(0 0 0 / 0.6);

  /* Surface elevation steps. --surface-1 is one step lighter than --base-bg
     for Linear/Raycast-style elevated panels (Panel frame="surface"). */
  --surface-1: #111111;

  --trans-fast: 0.15s ease;
  --radius: 0.25rem;
}

/* Light theme — available for package consumers via data-theme="light" */
[data-theme="light"] {
  /* Primitive base colors - Diffgazer Light Theme */
  --base-bg: #f7f8f5;
  --base-fg: #1f2328;
  --base-dim: #5f6872;
  --base-border: #aeb7c0;
  --base-highlight: #1f2328;
  --base-highlight-foreground: #ffffff;
  --base-input-bg: #ffffff;
  --base-muted: #69717a;
  --base-selection: #e8edf3;

  /* Accent colors */
  --base-info: #0b63ce;
  --base-accent: #6f42c1;
  --base-success: #0f7a4f;
  --base-danger: #c62828;
  --base-warning: #8a5a00;

  /* Code syntax palette (shared by Fumadocs + generated snippets) */
  --code-comment: var(--base-dim);
  --code-string: var(--base-accent);
  --code-number: var(--base-accent);
  --code-keyword: var(--base-info);
  --code-function: var(--base-success);
  --code-tag: var(--base-success);
  --code-attr: var(--base-info);
  --code-parameter: var(--base-warning);
  --code-operator: var(--base-danger);
  --code-variable: var(--base-fg);
  --code-type: var(--base-info);

  /* Semantic mappings */
  --background: var(--base-bg);
  --foreground: var(--base-fg);
  --primary: var(--base-highlight);
  --primary-foreground: var(--base-highlight-foreground);
  --secondary: var(--base-selection);
  --secondary-foreground: var(--base-fg);
  --muted: var(--base-muted);
  --muted-foreground: var(--base-dim);
  --border: var(--base-border);
  --input: var(--base-input-bg);
  --accent: var(--base-accent);
  --accent-foreground: var(--base-highlight-foreground);
  --card: var(--base-input-bg);
  --card-foreground: var(--base-fg);
  --popover: var(--base-input-bg);
  --popover-foreground: var(--base-fg);
  --ring: var(--base-info);
  --success: var(--base-success);
  --success-foreground: #ffffff;
  --warning: var(--base-warning);
  --warning-foreground: #ffffff;
  --info: var(--base-info);
  --info-foreground: #ffffff;
  --error: var(--base-danger);
  --error-foreground: #ffffff;

  --success-subtle: color-mix(in oklab, var(--base-success) 12%, transparent);
  --success-text: var(--base-success);
  --success-border: var(--base-success);
  --success-strong: var(--base-success);
  --success-strong-foreground: #ffffff;

  --warning-subtle: color-mix(in oklab, var(--base-warning) 8%, transparent);
  --warning-text: var(--base-warning);
  --warning-border: var(--base-warning);
  --warning-strong: var(--base-warning);
  --warning-strong-foreground: #ffffff;

  --error-subtle: color-mix(in oklab, var(--base-danger) 10%, transparent);
  --error-text: var(--base-danger);
  --error-border: var(--base-danger);
  --error-strong: var(--base-danger);
  --error-strong-foreground: #ffffff;

  --info-subtle: color-mix(in oklab, var(--base-info) 10%, transparent);
  --info-text: var(--base-info);
  --info-border: var(--base-info);
  --info-strong: var(--base-info);
  --info-strong-foreground: #ffffff;

  --neutral-subtle: color-mix(in oklab, var(--base-border) 8%, transparent);
  --neutral-border: var(--base-border);
  --neutral-text: var(--base-muted);
  --neutral-strong: var(--base-muted);
  --neutral-strong-foreground: #ffffff;

  --action: var(--base-accent);
  --action-foreground: #ffffff;

  /* Shared scrim for modal backdrops (same value across themes). */
  --scrim: rgb(0 0 0 / 0.6);

  /* Surface elevation steps. --surface-1 is the elevated surface vs
     --base-bg (Linear-style cards / Panel frame="surface"). */
  --surface-1: #ffffff;
}

/* Canonical style seed. Package builds and dgadd init append registry component CSS to this entry. */
@import "./theme.css";

/*
 * Callout primitive styles. Two orthogonal axes drive visual chrome via
 * data-attribute selectors on the callout root:
 *   [data-frame] = inline | rail | bar
 *   [data-tone]  = info | success | warning | error
 *
 * Tone cascades three CSS vars consumed by the icon, title, border, and
 * background:
 *   --callout-tone   foreground / icon / title color signal
 *   --callout-border perimeter color (used by inline + rail frames)
 *   --callout-subtle subtle background tint (used by inline + rail frames)
 *
 * Frame chrome (border, rail, bar background) is selected by [data-frame].
 * Grid layout (grid-template-areas) is driven by [data-frame] combined
 * with [data-has-icon] on the inner grid element. The icon column is
 * collapsed when no <Callout.Icon> child is present.
 *
 * For architectural parity with Panel (panel/panel.css), all chrome and
 * forced-colors fallbacks live in this file; the React component only emits
 * data-attributes.
 */
@layer components {
  /*
   * Default tone values are consumed via var() fallback (not declared on the
   * slot) so an ancestor-scoped override reaches them. Defaults: --callout-tone →
   * var(--foreground); --callout-border → var(--border); --callout-subtle → transparent.
   * The [data-tone] variants below still win.
   */
  [data-slot="callout"] {
    position: relative;
    font-family: var(--font-mono);
    font-size: 13px;
    color: var(--foreground);
    border-radius: var(--radius);
  }

  /* ============================================================
     Tone cascade — paints --callout-tone / --callout-border / --callout-subtle.
     ============================================================ */
  [data-slot="callout"][data-tone="info"] {
    --callout-tone: var(--info-text);
    --callout-border: var(--info-border);
    --callout-subtle: var(--info-subtle);
  }
  [data-slot="callout"][data-tone="success"] {
    --callout-tone: var(--success-text);
    --callout-border: var(--success-border);
    --callout-subtle: var(--success-subtle);
  }
  [data-slot="callout"][data-tone="warning"] {
    --callout-tone: var(--warning-text);
    --callout-border: var(--warning-border);
    --callout-subtle: var(--warning-subtle);
  }
  [data-slot="callout"][data-tone="error"] {
    --callout-tone: var(--error-text);
    --callout-border: var(--error-border);
    --callout-subtle: var(--error-subtle);
  }

  /* ============================================================
     Frame: inline (default) — full hairline border at tone color +
     subtle tone background.
     ============================================================ */
  [data-slot="callout"][data-frame="inline"] {
    border: 1px solid var(--callout-border, var(--border));
    background: var(--callout-subtle, transparent);
    padding: 12px 14px;
  }

  /* ============================================================
     Frame: rail — 2px inline-start rail at tone color, no perimeter,
     square corners, subtle tone background.
     ============================================================ */
  [data-slot="callout"][data-frame="rail"] {
    border: 0;
    border-inline-start: 2px solid var(--callout-border, var(--border));
    background: var(--callout-subtle, transparent);
    border-radius: 0;
    padding: 10px 14px;
  }

  /* ============================================================
     Frame: bar — neutral border + a 4px tone marker bar inside the
     grid (placed in the bar grid-area via the [data-slot="callout-bar"]
     rule below). Background is a 2% foreground wash for subtle elevation
     against the page.
     ============================================================ */
  [data-slot="callout"][data-frame="bar"] {
    border: 1px solid color-mix(in oklab, var(--border) 60%, transparent);
    background: color-mix(in oklab, var(--foreground) 2%, transparent);
    padding: 12px 14px;
  }
}

/* ============================================================
   Grid layout: the inner [data-slot="callout-grid"] element owns the
   grid, with columns + template areas driven by [data-frame] and its
   own [data-has-icon]. Each child takes its cell from its data-slot
   (the React components emit data-attributes only).
   ============================================================ */
@layer components {
  [data-slot="callout-grid"] {
    display: grid;
    align-items: start;
    column-gap: 10px;
    row-gap: 4px;
  }

  /* inline / rail columns. */
  [data-slot="callout-grid"][data-has-icon="false"] {
    grid-template-columns: minmax(0, 1fr) auto;
    grid-template-areas: "title dismiss" "body .";
  }
  [data-slot="callout-grid"][data-has-icon="true"] {
    grid-template-columns: 16px minmax(0, 1fr) auto;
    grid-template-areas: "icon title dismiss" ". body .";
  }

  /* bar frame prepends a 4px marker column. */
  [data-slot="callout"][data-frame="bar"] > [data-slot="callout-grid"][data-has-icon="false"] {
    grid-template-columns: 4px minmax(0, 1fr) auto;
    grid-template-areas: "bar title dismiss" "bar body .";
  }
  [data-slot="callout"][data-frame="bar"] > [data-slot="callout-grid"][data-has-icon="true"] {
    grid-template-columns: 4px 16px minmax(0, 1fr) auto;
    grid-template-areas: "bar icon title dismiss" "bar . body .";
  }

  /* Cell placement per child. */
  [data-slot="callout-bar"] {
    grid-area: bar;
  }
  [data-slot="callout-icon"] {
    grid-area: icon;
  }
  [data-slot="callout-title"] {
    grid-area: title;
  }
  [data-slot="callout-content"] {
    grid-area: body;
  }
  [data-slot="callout-dismiss"] {
    grid-area: dismiss;
  }
}

/* ============================================================
   Forced-colors: keep callout boundaries legible in Windows HCM.
   Mirrors Panel's forced-colors block in panel/panel.css.
   ============================================================ */
@media (forced-colors: active) {
  [data-slot="callout"][data-frame="inline"] {
    border-color: CanvasText;
  }
  [data-slot="callout"][data-frame="rail"] {
    border-inline-start-color: CanvasText;
  }
  [data-slot="callout"][data-frame="bar"] {
    border-color: CanvasText;
  }
}

/*
 * Panel primitive styles. Three orthogonal axes drive visual chrome via
 * data-attribute selectors on [data-slot="panel"]:
 *   [data-frame]   = hairline | rail | viewfinder | surface
 *   [data-tone]    = info | success | warning | error | accent
 *   [data-density] = default | compact
 *
 * Frame chrome (border, rail, viewfinder corners, surface) is selected by
 * [data-frame]. Tone tints --panel-tone (inherited by the header marker bar)
 * and the frame's color signal (border-color, rail color, corner color, or
 * surface header tint). Density propagates to header/content/footer padding.
 *
 * Adjacent panel-row siblings get an automatic top border for tabular layouts
 * (the rule consumers most commonly hand-rolled).
 */
@layer components {
  /*
   * Default component-token values are consumed via var() fallback (not
   * declared on the slot) so an ancestor-scoped override can reach them.
   * Defaults: --panel-bg → var(--background); --panel-fg → var(--foreground);
   * --panel-hairline → color-mix(in oklab, var(--border) 60%, transparent);
   * --panel-tone → var(--foreground). Tone variants below still win.
   */
  [data-slot="panel"] {
    position: relative;
    background: var(--panel-bg, var(--background));
    color: var(--panel-fg, var(--foreground));
    border-radius: var(--radius);
  }

  /* Density rhythm — single source of truth. */
  [data-slot="panel"][data-density="default"] [data-slot="panel-header"] {
    padding: 14px 20px 12px;
  }
  [data-slot="panel"][data-density="default"] [data-slot="panel-content"] {
    padding: 14px 20px;
  }
  [data-slot="panel"][data-density="default"] [data-slot="panel-footer"] {
    padding: 10px 20px;
  }
  [data-slot="panel"][data-density="compact"] [data-slot="panel-header"] {
    padding: 10px 14px 8px;
  }
  [data-slot="panel"][data-density="compact"] [data-slot="panel-content"] {
    padding: 10px 14px;
  }
  [data-slot="panel"][data-density="compact"] [data-slot="panel-footer"] {
    padding: 8px 14px;
  }

  /* Header. align-items: center so action chips sit on the title's vertical
     center; the marker bar uses align-self: stretch to span full header height. */
  [data-slot="panel-header"] {
    display: flex;
    gap: 12px;
    align-items: center;
  }
  [data-slot="panel-header"][data-marker="bar"]::before {
    content: "";
    flex: none;
    align-self: stretch;
    width: 4px;
    background: var(--panel-tone, var(--foreground));
    border-radius: 1px;
  }
  [data-slot="panel-header"] > [data-slot="panel-header-body"] {
    display: flex;
    flex-direction: column;
    gap: 4px;
    min-width: 0;
    flex: 1 1 auto;
  }
  [data-slot="panel-header"] > [data-slot="panel-header-end"] {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
  }

  /* Footer — flex row with space-between for primary text + meta badge. */
  [data-slot="panel-footer"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
  }

  /* Row primitive — adjacent siblings get the auto-divider. */
  [data-slot="panel-row"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    padding-block: 6px;
  }
  [data-slot="panel-row"] + [data-slot="panel-row"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Frame: hairline (default)
     ============================================================ */
  [data-slot="panel"][data-frame="hairline"] {
    border: 1px solid var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="hairline"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="hairline"] [data-slot="panel-footer"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Frame: rail — inline-start rail, hairline under header only.
     The rail IS the marker, so suppress the header bar.
     ============================================================ */
  [data-slot="panel"][data-frame="rail"] {
    border: 0;
    border-inline-start: 2px solid var(--border);
    border-radius: 0;
    padding-block: 2px;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
    padding-inline-start: 14px;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-header"][data-marker="bar"]::before {
    display: none;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-content"],
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-footer"] {
    padding-inline-start: 14px;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-footer"] {
    border: 0;
  }

  /* ============================================================
     Frame: viewfinder — four corner brackets. Shares the viewfinder
     visual language with diff-view via the same contract:
       - CSS vars: --viewfinder-size, --viewfinder-weight, --viewfinder-color, --viewfinder-offset
       - Corner element classes: .vf-tl / .vf-tr / .vf-bl / .vf-br
     Dialog uses a separate `.dlg-corners` + [data-corners] pattern
     for its own (in-flow vs. modal) reasons, so there is no literal
     `.viewfinder` class to share across all three components today.
     ============================================================ */
  [data-slot="panel"][data-frame="viewfinder"] {
    --viewfinder-size: 20px;
    --viewfinder-weight: 2px;
    --viewfinder-color: var(--foreground);
    --viewfinder-offset: 0px;
    padding: 8px;
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > span {
    position: absolute;
    pointer-events: none;
    width: var(--viewfinder-size);
    height: var(--viewfinder-size);
    border: 0 solid var(--viewfinder-color);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-tl {
    top: var(--viewfinder-offset);
    left: var(--viewfinder-offset);
    border-top-width: var(--viewfinder-weight);
    border-left-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-tr {
    top: var(--viewfinder-offset);
    right: var(--viewfinder-offset);
    border-top-width: var(--viewfinder-weight);
    border-right-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-bl {
    bottom: var(--viewfinder-offset);
    left: var(--viewfinder-offset);
    border-bottom-width: var(--viewfinder-weight);
    border-left-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-br {
    bottom: var(--viewfinder-offset);
    right: var(--viewfinder-offset);
    border-bottom-width: var(--viewfinder-weight);
    border-right-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-footer"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Frame: surface — elevated --surface-1 background, transparent
     border (forced-colors fallback), inner top highlight.
     ============================================================ */
  [data-slot="panel"][data-frame="surface"] {
    background: var(--surface-1);
    border: 1px solid transparent;
    box-shadow: inset 0 1px 0 color-mix(in oklab, var(--foreground) 4%, transparent);
  }
  [data-slot="panel"][data-frame="surface"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="surface"] [data-slot="panel-footer"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Tone — paints --panel-tone (the header marker bar) and the
     frame's color signal. Tone is a pure visual cue; semantic
     status messaging belongs in Callout (see callout.css).
     ============================================================ */
  [data-slot="panel"][data-tone="info"] {
    --panel-tone: var(--info-text);
  }
  [data-slot="panel"][data-tone="success"] {
    --panel-tone: var(--success-text);
  }
  [data-slot="panel"][data-tone="warning"] {
    --panel-tone: var(--warning-text);
  }
  [data-slot="panel"][data-tone="error"] {
    --panel-tone: var(--error-text);
  }
  [data-slot="panel"][data-tone="accent"] {
    --panel-tone: var(--action);
  }

  /* Hairline frame: border + bar adopt the tone color. */
  [data-slot="panel"][data-frame="hairline"][data-tone="info"] {
    border-color: var(--info-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="success"] {
    border-color: var(--success-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="warning"] {
    border-color: var(--warning-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="error"] {
    border-color: var(--error-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="accent"] {
    border-color: var(--action);
  }

  /* Rail frame: rail color. */
  [data-slot="panel"][data-frame="rail"][data-tone="info"] {
    border-inline-start-color: var(--info-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="success"] {
    border-inline-start-color: var(--success-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="warning"] {
    border-inline-start-color: var(--warning-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="error"] {
    border-inline-start-color: var(--error-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="accent"] {
    border-inline-start-color: var(--action);
  }

  /* Viewfinder frame: corner color. */
  [data-slot="panel"][data-frame="viewfinder"][data-tone="info"] {
    --viewfinder-color: var(--info-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="success"] {
    --viewfinder-color: var(--success-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="warning"] {
    --viewfinder-color: var(--warning-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="error"] {
    --viewfinder-color: var(--error-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="accent"] {
    --viewfinder-color: var(--action);
  }

  /* Surface frame: subtle header tint + colored bottom-border on header. */
  [data-slot="panel"][data-frame="surface"][data-tone="info"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--info-text) 6%, transparent);
    border-block-end-color: var(--info-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="success"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--success-text) 6%, transparent);
    border-block-end-color: var(--success-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="warning"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--warning-text) 8%, transparent);
    border-block-end-color: var(--warning-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="error"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--error-text) 8%, transparent);
    border-block-end-color: var(--error-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="accent"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--action) 6%, transparent);
    border-block-end-color: var(--action);
  }
}

/* ============================================================
   Forced-colors: keep panel boundaries legible in Windows HCM.
   Rail and surface frames need an explicit perimeter cue.
   ============================================================ */
@media (forced-colors: active) {
  [data-slot="panel"][data-frame="hairline"],
  [data-slot="panel"][data-frame="surface"] {
    border-color: CanvasText;
  }
  [data-slot="panel"][data-frame="rail"] {
    border-inline-start-color: CanvasText;
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > span {
    border-color: CanvasText;
  }
  [data-slot="panel-header"][data-marker="bar"]::before {
    background: CanvasText;
  }
}

@layer base {
  dialog {
    --dialog-duration: 0.15s;
    padding: 0;
    border: none;
    background: transparent;
    overflow: visible;
  }
}

@layer components {
  dialog::backdrop {
    background: var(--scrim);
    -webkit-backdrop-filter: blur(4px);
    backdrop-filter: blur(4px);
  }

  dialog[data-state="open"]::backdrop {
    animation: backdrop-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"]::backdrop {
    animation: backdrop-out var(--dialog-duration) ease-in forwards;
  }

  dialog[data-state="open"] {
    animation: dialog-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"] {
    animation: dialog-out var(--dialog-duration) ease-in forwards;
    pointer-events: none;
  }

  /*
   * Scroll lock contract.
   * Native <dialog>.showModal() does not lock body scroll on its own. This
   * CSS-only lock activates whenever any descendant <dialog> exposes the
   * [open] attribute, and unlocks once every dialog closes.
   * scrollbar-gutter: stable avoids a horizontal layout shift when the
   * scrollbar is hidden under hidden-overflow.
   *
   * Limits (consumers in these cases must opt into a JS lock):
   *   - Custom scroll roots: only the <body> is locked. Apps that scroll on
   *     <html>, a wrapping element, or a scroll container handle their own
   *     scroll lock.
   *   - iOS Safari rubber-band: overflow:hidden on body does not prevent
   *     touchmove from scrolling the visual viewport.
   *   - :has() support floor: Chrome 105+, Safari 15.4+, Firefox 121+ — older
   *     engines do not get any body lock.
   */
  body:has(dialog[open]) {
    overflow: hidden;
    scrollbar-gutter: stable;
  }
}

@keyframes dialog-in {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes dialog-out {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.95);
  }
}

@keyframes backdrop-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes backdrop-out {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  dialog,
  dialog::backdrop {
    /* biome-ignore lint/complexity/noImportantStyles: prefers-reduced-motion override must defeat the dialog animation declarations regardless of specificity. */
    animation: none !important;
  }
}

/*
 * DialogContent corner accents. Four corners total: dialog::before/::after =
 * top corners, dialog > .dlg-corners::before/::after = bottom corners. The
 * .dlg-corners span is only rendered when corners !== "none" so the
 * default path stays a plain CSS rectangle.
 */
@layer components {
  /*
   * Default corner-token values are consumed via var() fallback at the corner
   * use sites below (not declared on the slot) so an ancestor-scoped override
   * reaches them. Defaults: --viewfinder-size → 18px; --viewfinder-weight → 2px;
   * --viewfinder-color → var(--foreground); --viewfinder-offset → 0px. The
   * per-corner variant overrides below still win.
   */
  [data-slot="dialog-content"][data-corners="subtle"] {
    --viewfinder-size: 12px;
    --viewfinder-weight: 1.5px;
    --viewfinder-color: var(--border);
  }

  [data-slot="dialog-content"][data-corners="bold"] {
    --viewfinder-size: 28px;
    --viewfinder-weight: 3px;
  }

  [data-slot="dialog-content"][data-corners="outset"] {
    --viewfinder-offset: -3px;
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::before,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::after,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::before,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::after {
    content: "";
    position: absolute;
    width: var(--viewfinder-size, 18px);
    height: var(--viewfinder-size, 18px);
    border: 0 solid var(--viewfinder-color, var(--foreground));
    pointer-events: none;
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::before {
    top: var(--viewfinder-offset, 0px);
    left: var(--viewfinder-offset, 0px);
    border-top-width: var(--viewfinder-weight, 2px);
    border-left-width: var(--viewfinder-weight, 2px);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::after {
    top: var(--viewfinder-offset, 0px);
    right: var(--viewfinder-offset, 0px);
    border-top-width: var(--viewfinder-weight, 2px);
    border-right-width: var(--viewfinder-weight, 2px);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::before {
    bottom: var(--viewfinder-offset, 0px);
    left: var(--viewfinder-offset, 0px);
    border-bottom-width: var(--viewfinder-weight, 2px);
    border-left-width: var(--viewfinder-weight, 2px);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::after {
    bottom: var(--viewfinder-offset, 0px);
    right: var(--viewfinder-offset, 0px);
    border-bottom-width: var(--viewfinder-weight, 2px);
    border-right-width: var(--viewfinder-weight, 2px);
  }
}

/*
 * DialogTitle eyebrow meta tag typography tokens. Centralized here so consumers
 * can override the meta size/tracking globally without editing the primitive.
 */
@layer components {
  [data-slot="dialog-content"] {
    --dialog-title-meta-size: 11px;
    --dialog-title-meta-tracking: 0.08em;
  }
}

/*
 * Inset for the optional Dialog.CloseIcon (top-right). Default clears the
 * dialog edge; per-corner overrides push the button inward so it does not
 * collide with the corner accents.
 *   subtle  : 12px arms + 4px = 16px
 *   standard: 18px arms + 4px = 22px
 *   outset  : 18px arms (shifted -3px outside) + 4px ≈ 22px
 *   bold    : 28px arms + 4px = 32px
 */
@layer components {
  [data-slot="dialog-content"] {
    --dialog-close-btn-inset: 0.5rem;
  }

  [data-slot="dialog-content"][data-corners="subtle"] {
    --dialog-close-btn-inset: 16px;
  }

  [data-slot="dialog-content"][data-corners="standard"],
  [data-slot="dialog-content"][data-corners="outset"] {
    --dialog-close-btn-inset: 22px;
  }

  [data-slot="dialog-content"][data-corners="bold"] {
    --dialog-close-btn-inset: 32px;
  }
}

/*
 * Stepper variant CSS contract.
 *
 * Three things live in real CSS (not Tailwind utilities):
 *
 *   1. The `ascii` active-state blinking cursor (custom @keyframes). Wrapped
 *      in motion-safe Tailwind utility on the consuming side; the keyframes
 *      themselves are declared here.
 *   2. The `numbered` variant's CSS counter — the digit shown in pending and
 *      active states comes from `counter(step)` rendered through `::before`
 *      on the indicator span. Tailwind's arbitrary value support for
 *      `content-[counter(...)]` is unreliable across compilers.
 *   3. The vertical connector line between steps. Composed via utilities the
 *      connector clamped to a 2px sliver because `bottom: 0` plus a 30px
 *      `<li>` left no room to draw. Real CSS lets the line overshoot the
 *      `<li>` boundary so it visually bridges into the next indicator at any
 *      row height. The `left` offset is variant-specific and centred on the
 *      indicator column width (1ch ASCII → centred on the `x` in `[x]`, 20px
 *      numbered square → centred at 10px, 1ch bullet → centred at 4px).
 */

@keyframes stepper-blink {
  50% {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  /*
   * Keep the cursor visible but stop animating it. The .motion-safe: utility
   * on the consumer prevents the animation property from being set in the
   * first place, but this guard catches any direct usage of the keyframes
   * elsewhere.
   */
  [data-variant="ascii"] [data-stepper-cursor] {
    /* biome-ignore lint/complexity/noImportantStyles: prefers-reduced-motion override must defeat the cursor keyframes regardless of specificity. */
    animation: none !important;
  }
}

/*
 * Numbered indicator: render `counter(step)` for pending and active cells.
 * Completed/error/skipped/disabled render an explicit glyph in JSX and the
 * counter span is absent from the tree.
 *
 * The CSS counter is established on the <ol data-variant="numbered"> via the
 * `[counter-reset:step]` Tailwind utility and incremented on each <li> via
 * `[counter-increment:step]`. This rule paints the digit on the indicator
 * span whose JSX renders an empty `[data-counter]` placeholder.
 */
[data-variant="numbered"] [data-counter]::before {
  content: counter(step);
}

/*
 * Vertical connector — shared geometry for ASCII, numbered, and bullet
 * variants. `tag` and `progress` opt out (no rule). The `<li>` itself is
 * positioned `relative` via the Tailwind base. Scoped to
 * `[data-orientation="vertical"]` so the horizontal stepper's numbered
 * variant (which has its own behind-the-square horizontal bar) is untouched.
 *
 * `top: 36px` clears the indicator glyph (sits at row top with `py-4`, so
 * the glyph bottom edge lands at ~34px and the connector starts ~2px below).
 * `bottom: -8px` overshoots the `<li>` boundary modestly so the line visually
 * bridges into the next step's connector without dominating the row height —
 * the row breathes around a short connector segment rather than a long line.
 * The last step suppresses the connector.
 */
[data-orientation="vertical"][data-variant="ascii"] > li:not(:last-child)::before,
[data-orientation="vertical"][data-variant="numbered"] > li:not(:last-child)::before,
[data-orientation="vertical"][data-variant="bullet"] > li:not(:last-child)::before {
  content: "";
  position: absolute;
  top: 36px;
  bottom: -8px;
  width: 1px;
  background: var(--border);
}

/*
 * Per-variant horizontal alignment of the connector. Each value centres the
 * 1px line on the visual middle of the indicator column.
 */
[data-orientation="vertical"][data-variant="ascii"] > li:not(:last-child)::before {
  /* `[x]` is 3 mono chars wide; centre on the `x` (1.5ch from the left edge). */
  left: calc(1.5ch + 0.5px);
}

[data-orientation="vertical"][data-variant="numbered"] > li:not(:last-child)::before {
  /* 20px square indicator → centre at 10px (½px nudge keeps the 1px line crisp). */
  left: 9.5px;
  /* Square bottom sits at ~36px (16px paddingTop + 20px square). Push the
   * connector start 2px below the square so it doesn't paint over the border. */
  top: 38px;
}

[data-orientation="vertical"][data-variant="bullet"] > li:not(:last-child)::before {
  /* 1ch indicator → centre at ½ch. Dashed style differentiates the low-chrome variant. */
  left: calc(0.5ch + 0.5px);
  background: transparent;
  border-left: 1px dashed var(--border);
  width: 0;
}

/*
 * Completed steps recolour the connector so a finished segment reads as a
 * filled timeline. Bullet uses `border-left-color` because the connector is
 * a border, not a background.
 */
[data-orientation="vertical"][data-variant="ascii"]
  > li[data-status="completed"]:not(:last-child)::before,
[data-orientation="vertical"][data-variant="numbered"]
  > li[data-status="completed"]:not(:last-child)::before {
  background: var(--success);
}

[data-orientation="vertical"][data-variant="bullet"]
  > li[data-status="completed"]:not(:last-child)::before {
  border-left-color: var(--success);
}

/*
 * CodeBlock primitive styles. The component renders three variants
 * keyed via [data-slot="code-block"][data-variant="..."] on the root
 * <figure>. Shared typography lives on the root; per-variant chrome
 * lives in its own block. Token color classes (.code-*) and the
 * highlight.js (.hljs-*) compatibility map are kept here so consumers
 * get correct colors out of the box once code-block/code-block.css is loaded.
 */
@layer components {
  /*
   * Default component-token values are consumed via var() fallback so an
   * ancestor-scoped override reaches them. Defaults: --code-block-bg → var(--background);
   * --code-block-fg → var(--foreground); --code-block-border → var(--border); --code-block-border-soft →
   * color-mix(in oklab, var(--border) 60%, transparent); --code-block-muted →
   * var(--muted-foreground); --code-block-header-h → 32px.
   */
  [data-slot="code-block"] {
    position: relative;
    display: block;
    margin: 0;
    background: var(--code-block-bg, var(--background));
    color: var(--code-block-fg, var(--foreground));
    overflow: hidden;
    border-radius: 2px;
  }

  [data-slot="code-block-content"] {
    margin: 0;
    padding: 12px 0;
    font-family: var(--base-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
    font-size: 13px;
    line-height: 1.45;
    letter-spacing: 0;
    font-feature-settings:
      "calt" 0,
      "liga" 0,
      "zero" 1,
      "ss01" 1;
    font-variant-ligatures: none;
    font-variant-numeric: tabular-nums;
  }

  [data-slot="code-block-content"] > code {
    display: block;
    padding-inline: 12px;
  }

  [data-slot="code-block"] [data-slot="code-block-line"] {
    display: flex;
    align-items: baseline;
    padding-left: 12px;
    padding-right: 12px;
    /* Preserve row height for empty source lines (replaces U+200B fallback). */
    min-height: 1.45em;
  }

  [data-slot="code-block-line-number"] {
    flex: 0 0 auto;
    width: var(--code-block-line-number-w, 2ch);
    min-width: var(--code-block-line-number-w, 2ch);
    padding-right: 12px;
    text-align: right;
    user-select: none;
    /* 65% of foreground keeps line numbers ≥4.5:1 in both themes (was 50% muted ≈2.6:1). */
    color: color-mix(in oklab, var(--code-block-fg, var(--foreground)) 65%, transparent);
  }

  [data-slot="code-block-line-sign"] {
    flex: 0 0 1ch;
    padding-right: 6px;
    text-align: center;
    user-select: none;
    color: color-mix(in oklab, var(--code-block-muted, var(--muted-foreground)) 70%, transparent);
  }

  [data-slot="code-block-line"] > code {
    white-space: pre;
    min-width: 0;
    flex: 1 1 auto;
  }

  /* Row state tints applied to the line, not <code>. */
  [data-slot="code-block-line"][data-line-state="added"] {
    background: color-mix(in oklab, var(--success, #2ea043) 12%, transparent);
  }

  [data-slot="code-block-line"][data-line-state="added"] [data-slot="code-block-line-sign"] {
    color: color-mix(
      in oklab,
      var(--success, #2ea043) 90%,
      var(--code-block-fg, var(--foreground))
    );
  }

  [data-slot="code-block-line"][data-line-state="removed"] {
    background: color-mix(in oklab, var(--error, #f85149) 12%, transparent);
  }

  [data-slot="code-block-line"][data-line-state="removed"] [data-slot="code-block-line-sign"] {
    color: color-mix(in oklab, var(--error, #f85149) 90%, var(--code-block-fg, var(--foreground)));
  }

  [data-slot="code-block-line"][data-line-state="highlight"] {
    background: color-mix(in oklab, var(--code-block-fg, var(--foreground)) 8%, transparent);
  }

  /* Header chrome. */
  [data-slot="code-block-header"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: var(--code-block-header-h, 32px);
    padding: 0 12px;
    border-bottom: 1px solid
      var(--code-block-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
  }

  [data-slot="code-block-label"] {
    font-family: var(--base-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
    font-size: 12px;
    font-weight: 400;
    line-height: 1;
    color: color-mix(in oklab, var(--code-block-fg, var(--foreground)) 80%, transparent);
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  /* Variant: hairline (default). */
  [data-slot="code-block"][data-variant="hairline"] {
    border: 1px solid
      var(--code-block-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* Variant: bare. */
  [data-slot="code-block"][data-variant="bare"] {
    border: 0;
    border-left: 2px solid var(--code-block-border, var(--border));
    background: transparent;
    border-radius: 0;
    transition: border-color 120ms ease;
  }

  [data-slot="code-block"][data-variant="bare"]:hover {
    border-left-color: var(--ring, var(--code-block-fg, var(--foreground)));
  }

  [data-slot="code-block"][data-variant="bare"] [data-slot="code-block-header"] {
    display: none;
  }

  /* Variant: terminal. */
  [data-slot="code-block"][data-variant="terminal"] {
    border: 1px solid
      var(--code-block-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
  }

  [data-slot="code-block"][data-variant="terminal"] [data-slot="code-block-header"] {
    position: relative;
    justify-content: center;
  }

  /* Chrome="dots" anywhere: anchor dots to the header strip, balance the
     centered label with symmetric padding (12px outer + 3*9 dots + 2*6 gaps
     ≈ 51 → round to 52). */
  [data-slot="code-block"][data-chrome="dots"] [data-slot="code-block-header"] {
    position: relative;
    justify-content: center;
    padding-inline: 52px;
  }

  [data-slot="code-block-dots"] {
    /* Anchor to the header strip (cb-header-h tall), not the figure midpoint,
       so dots sit beside the centered title regardless of content length. */
    position: absolute;
    left: 12px;
    top: 0;
    height: var(--code-block-header-h, 32px);
    display: inline-flex;
    align-items: center;
    gap: 6px;
    pointer-events: none;
  }

  [data-slot="code-block-dots"] span {
    width: 9px;
    height: 9px;
    border-radius: 50%;
    background: color-mix(in oklab, var(--code-block-border, var(--border)) 70%, transparent);
  }

  /* Self-protecting: hide chrome dots if no header is rendered. */
  [data-slot="code-block"]:not(:has([data-slot="code-block-header"]))
    [data-slot="code-block-dots"] {
    display: none;
  }

  /* Copy button. */
  [data-slot="code-block-copy-button"] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 24px;
    height: 24px;
    padding: 0;
    margin: 0;
    background: transparent;
    border: 0;
    border-radius: 2px;
    color: color-mix(in oklab, var(--code-block-fg, var(--foreground)) 60%, transparent);
    cursor: pointer;
    transition:
      color 120ms ease,
      background-color 120ms ease;
  }

  [data-slot="code-block-copy-button"]:hover {
    color: var(--code-block-fg, var(--foreground));
    background: color-mix(in oklab, var(--code-block-fg, var(--foreground)) 8%, transparent);
  }

  [data-slot="code-block-copy-button"][data-state="copied"] {
    color: var(--success, #2ea043);
  }

  [data-slot="code-block-copy-button"]:focus-visible {
    outline: 2px solid var(--ring, var(--code-block-fg, var(--foreground)));
    outline-offset: 2px;
  }

  /* Focus ring on the scrollable region. */
  [data-slot="code-block-content"]:focus-visible {
    outline: 2px solid var(--ring, var(--code-block-fg, var(--foreground)));
    outline-offset: 2px;
  }

  /* Token color classes, addressable from inline-tokenized content
     (CodeBlockToken { className }) and from the lowlight-emitted
     hljs-* classes via the compatibility map below. */
  [data-slot="code-block"] .code-comment,
  [data-slot="code-block"] .hljs-comment,
  [data-slot="code-block"] .hljs-quote {
    color: var(--code-comment);
    font-style: italic;
  }

  [data-slot="code-block"] .code-string,
  [data-slot="code-block"] .hljs-string,
  [data-slot="code-block"] .hljs-symbol,
  [data-slot="code-block"] .hljs-bullet,
  [data-slot="code-block"] .hljs-regexp {
    color: var(--code-string);
  }

  [data-slot="code-block"] .code-number,
  [data-slot="code-block"] .hljs-number,
  [data-slot="code-block"] .hljs-literal {
    color: var(--code-number);
  }

  [data-slot="code-block"] .code-keyword,
  [data-slot="code-block"] .hljs-keyword,
  [data-slot="code-block"] .hljs-selector-tag,
  [data-slot="code-block"] .hljs-meta-keyword {
    color: var(--code-keyword);
  }

  [data-slot="code-block"] .code-function,
  [data-slot="code-block"] .hljs-title,
  [data-slot="code-block"] .hljs-title.function_,
  [data-slot="code-block"] .hljs-section {
    color: var(--code-function);
  }

  [data-slot="code-block"] .code-tag,
  [data-slot="code-block"] .hljs-tag,
  [data-slot="code-block"] .hljs-name {
    color: var(--code-tag);
  }

  [data-slot="code-block"] .code-attr,
  [data-slot="code-block"] .hljs-attr,
  [data-slot="code-block"] .hljs-attribute {
    color: var(--code-attr);
  }

  [data-slot="code-block"] .code-parameter,
  [data-slot="code-block"] .hljs-params {
    color: var(--code-parameter);
  }

  [data-slot="code-block"] .code-operator,
  [data-slot="code-block"] .hljs-operator,
  [data-slot="code-block"] .hljs-punctuation {
    color: var(--code-operator);
  }

  [data-slot="code-block"] .code-variable,
  [data-slot="code-block"] .hljs-variable,
  [data-slot="code-block"] .hljs-template-variable {
    color: var(--code-variable);
  }

  [data-slot="code-block"] .code-type,
  [data-slot="code-block"] .hljs-type,
  [data-slot="code-block"] .hljs-built_in,
  [data-slot="code-block"] .hljs-class .hljs-title {
    color: var(--code-type);
  }
}

@media (prefers-reduced-motion: reduce) {
  [data-slot="code-block"][data-variant="bare"],
  [data-slot="code-block-copy-button"] {
    transition: none;
  }
}

@media (forced-colors: active) {
  [data-slot="code-block"][data-variant="hairline"],
  [data-slot="code-block"][data-variant="terminal"] {
    border-color: CanvasText;
  }

  [data-slot="code-block"][data-variant="bare"] {
    border-left-color: CanvasText;
  }

  [data-slot="code-block-content"]:focus-visible,
  [data-slot="code-block-copy-button"]:focus-visible {
    outline-color: Highlight;
  }
}

/*
 * DiffView primitive styles. The component renders five variants keyed via
 * [data-slot="diff-view"][data-variant="..."] on the root <figure>. Shared
 * typography and the grid-based row layout live on the root; per-variant
 * chrome (border, corners, strip, status bar) lives in its own block. All
 * row state (added/removed/context/hunk/empty) is driven by [data-state]
 * attributes — never inline styles — so the contract is CSP-safe.
 */
@layer components {
  [data-slot="diff-view"] {
    /* Default --diff-view-* values are consumed via var() fallback so an ancestor
       override reaches them: --diff-view-bg → var(--background); --diff-view-fg →
       var(--foreground); --diff-view-border → var(--border); --diff-view-border-soft →
       color-mix(in oklab, var(--border) 50%, transparent); --diff-view-muted →
       var(--muted-foreground). */

    /* Diff-only palette anchors. These are intentionally independent of the
       global --success/--error/--accent tokens because product themes
       may desaturate those for non-diff UI (e.g. the minimal theme maps
       --success to white). A diff that lost its red/green signal would be
       unreadable, so we ship GitHub-tuned defaults here and let consumers
       swap via [data-diff-palette], the light-theme tier below, or a
       per-instance custom property override. */
    --diff-color-add: #56d364;
    --diff-color-remove: #ff7b72;
    --diff-color-hunk: #79b8ff;

    /* Derived row tints. Percent tiers: ~14% subtle row tint, ~32% strong
       word-diff overlay, ~16% hunk separator, ~18% neutral empty-pane fill. */
    --diff-added-bg: color-mix(in oklab, var(--diff-color-add) 14%, transparent);
    --diff-added-bg-strong: color-mix(in oklab, var(--diff-color-add) 32%, transparent);
    --diff-removed-bg: color-mix(in oklab, var(--diff-color-remove) 14%, transparent);
    --diff-removed-bg-strong: color-mix(in oklab, var(--diff-color-remove) 32%, transparent);
    --diff-hunk-bg: color-mix(in oklab, var(--diff-color-hunk) 16%, transparent);
    --diff-hunk-fg: color-mix(
      in oklab,
      var(--diff-color-hunk) 70%,
      var(--diff-view-fg, var(--foreground))
    );
    --diff-line-num-fg: color-mix(
      in oklab,
      var(--diff-view-muted, var(--muted-foreground)) 90%,
      transparent
    );
    --diff-marker-fg: var(--diff-view-muted, var(--muted-foreground));
    --diff-empty-bg: color-mix(
      in oklab,
      var(--diff-view-muted, var(--muted-foreground)) 18%,
      transparent
    );

    position: relative;
    display: block;
    margin: 0;
    background: var(--diff-view-bg, var(--background));
    color: var(--diff-view-fg, var(--foreground));
    overflow: hidden;
    font-family: var(--base-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
    font-size: 13px;
    line-height: 1.5;
    font-feature-settings:
      "calt" 0,
      "liga" 0,
      "zero" 1;
    font-variant-ligatures: none;
    font-variant-numeric: tabular-nums;
    letter-spacing: 0;
  }

  [data-slot="diff-view"][data-density="compact"] {
    font-size: 12px;
    line-height: 1.45;
  }
  [data-slot="diff-view"][data-density="comfortable"] {
    font-size: 14px;
    line-height: 1.6;
  }

  /* Okabe-Ito colorblind-safe palette (dark tier). Sky-blue add anchor keeps
     ≥4.5:1 on #0a0a0a (the #0072b2 blue fails at 3.82:1). */
  [data-slot="diff-view"][data-diff-palette="okabe-ito"] {
    --diff-color-add: #56b4e9;
    --diff-color-remove: #d55e00;
    --diff-added-bg: color-mix(in oklab, var(--diff-color-add) 18%, transparent);
    --diff-added-bg-strong: color-mix(in oklab, var(--diff-color-add) 40%, transparent);
    --diff-removed-bg: color-mix(in oklab, var(--diff-color-remove) 18%, transparent);
    --diff-removed-bg-strong: color-mix(in oklab, var(--diff-color-remove) 40%, transparent);
  }

  /* Light-theme diff signal. The default anchors are dark-tuned; under the
     supported light theme re-anchor the +/− markers to GitHub-light values
     so the red/green signal stays ≥4.5:1 on #f7f8f5 (WCAG 1.4.3). Derived
     row/word tints re-resolve automatically from these cascaded anchors. */
  [data-theme="light"] [data-slot="diff-view"] {
    --diff-color-add: #1a7f37;
    --diff-color-remove: #cf222e;
    --diff-color-hunk: #0969da;
  }

  /* Light Okabe-Ito tier — colorblind-safe pair tuned for #f7f8f5. */
  [data-theme="light"] [data-slot="diff-view"][data-diff-palette="okabe-ito"] {
    --diff-color-add: #00795a;
    --diff-color-remove: #b34700;
  }

  /* File header (figcaption). */
  [data-slot="diff-view-caption"] {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 12px;
    font-size: 12px;
    color: var(--diff-view-fg, var(--foreground));
    border-bottom: 1px solid
      color-mix(in oklab, var(--diff-view-border, var(--border)) 40%, transparent);
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  /* Rows container — grid + subgrid + horizontal scroll. The [code] track grows
     to the widest line's content (see .diff-code), so the grid overflows the
     container and every subgrid row (grid-column: 1 / -1) spans the full
     scrollable width — keeping each row's state tint continuous when scrolled. */
  [data-slot="diff-view-rows"] {
    display: grid;
    grid-template-columns:
      [num-l] minmax(2.5ch, max-content)
      [num-r] minmax(2.5ch, max-content)
      [marker] 1.25ch
      [code] 1fr;
    overflow-x: auto;
    overflow-y: hidden;
    scrollbar-width: thin;
    scrollbar-color: var(--diff-view-border, var(--border)) var(--diff-view-bg, var(--background));
  }

  [data-slot="diff-view-rows"][data-line-numbers="false"] {
    grid-template-columns: [marker] 1.25ch [code] 1fr;
  }

  /* Split-side rows: single number column (per pane), with its own
     horizontal scroll. min-width: 0 resets default grid min-content so
     the pane truly clips at its 1fr column. */
  [data-slot="diff-view-rows"][data-side] {
    grid-template-columns:
      [num] minmax(2.5ch, max-content)
      [marker] 1.25ch
      [code] 1fr;
    min-width: 0;
  }

  [data-slot="diff-view-rows"][data-side][data-line-numbers="false"] {
    grid-template-columns: [marker] 1.25ch [code] 1fr;
  }

  [data-slot="diff-view-rows"]:focus-visible {
    outline: 2px solid var(--ring, var(--diff-view-fg, var(--foreground)));
    outline-offset: -2px;
  }

  /* Split container — two side-by-side panes. */
  [data-slot="diff-view-split"] {
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  }

  [data-slot="diff-view-split"] > [data-slot="diff-view-rows"] {
    border-right: 1px solid
      color-mix(in oklab, var(--diff-view-border, var(--border)) 30%, transparent);
  }
  [data-slot="diff-view-split"] > [data-slot="diff-view-rows"]:last-child {
    border-right: none;
  }

  /* Row + cells. Each row uses subgrid so cells align across rows. */
  [data-slot="diff-view-rows"] > [data-row] {
    display: grid;
    grid-template-columns: subgrid;
    grid-column: 1 / -1;
    min-width: max-content;
  }

  [data-row] > .diff-num,
  [data-row] > .diff-marker,
  [data-row] > .diff-code {
    padding-block: 1px;
  }

  [data-row][data-state="added"] {
    background: var(--diff-added-bg);
  }
  [data-row][data-state="removed"] {
    background: var(--diff-removed-bg);
  }
  [data-row][data-state="hunk"] {
    background: var(--diff-hunk-bg);
    color: var(--diff-hunk-fg);
  }
  [data-row][data-state="empty"] {
    background: var(--diff-empty-bg);
  }
  [data-row][data-highlighted] {
    box-shadow: inset 2px 0 0 0 var(--ring, var(--diff-view-fg, var(--foreground)));
  }

  .diff-num {
    color: var(--diff-line-num-fg);
    text-align: right;
    padding-inline: 0.5ch;
    user-select: none;
  }

  /* Marker cell — copy-paste keeps the +/− glyph (delta / git compat). */
  .diff-marker {
    color: var(--diff-marker-fg);
    text-align: center;
    user-select: text;
  }

  [data-row][data-state="added"] .diff-marker {
    color: var(--diff-color-add);
  }
  [data-row][data-state="removed"] .diff-marker {
    color: var(--diff-color-remove);
  }

  .diff-code {
    white-space: pre;
    padding-inline-end: 1ch;
    padding-inline-start: 0.5ch;
    /* Keep the code cell's intrinsic (content) minimum — do NOT collapse it to
       min-width: 0. It is the only content-sized cell in the [code] 1fr track,
       so its min-content is what grows that track (and every subgrid row spanning
       it) to the widest line. Collapsing it strands the row state tints at the
       visible width when the diff is scrolled horizontally. */
  }

  [data-row][data-state="hunk"] .diff-code {
    color: var(--diff-hunk-fg);
  }

  /* Word-diff spans stack on top of the row tint with the strong tier. */
  [data-word="added"] {
    background: var(--diff-added-bg-strong);
    border-radius: 2px;
    padding: 0 1px;
  }
  [data-word="removed"] {
    background: var(--diff-removed-bg-strong);
    border-radius: 2px;
    padding: 0 1px;
  }

  /* Optional vertical scroll wrapper — opt-in via [data-max-h] on the root.
     Applies to both unified and split: the entire diff body gets a fixed
     max-height; horizontal scroll still works per-row-block. */
  [data-slot="diff-view"][data-max-h] [data-slot="diff-view-scroll-v"] {
    max-height: var(--diff-view-max-h, 240px);
    overflow-y: auto;
    scrollbar-width: thin;
    scrollbar-color: var(--diff-view-border, var(--border)) var(--diff-view-bg, var(--background));
  }

  /* "No changes" status row. */
  [data-slot="diff-view-empty"] {
    padding: 16px;
    text-align: center;
    color: var(--diff-view-muted, var(--muted-foreground));
    font-size: 13px;
  }

  /* ============================================================
     Variant: hairline (default) — dashboard-grade safe default.
     ============================================================ */
  [data-slot="diff-view"][data-variant="hairline"] {
    border: 1px solid
      var(--diff-view-border-soft, color-mix(in oklab, var(--border) 50%, transparent));
    border-radius: 2px;
  }

  /* ============================================================
     Variant: bare — inline docs / changelogs, no chrome.
     ============================================================ */
  [data-slot="diff-view"][data-variant="bare"] {
    background: transparent;
    border: 0;
    border-left: 2px solid
      color-mix(in oklab, var(--diff-view-border, var(--border)) 60%, transparent);
    border-radius: 0;
    padding-left: 12px;
    transition: border-color 120ms ease;
  }

  [data-slot="diff-view"][data-variant="bare"]:hover {
    border-left-color: var(--ring, var(--diff-view-fg, var(--foreground)));
  }

  /* ============================================================
     Variant: dense — Gerrit / Reviewable density.
     Compact font, visible 1px dividers between number columns.
     ============================================================ */
  [data-slot="diff-view"][data-variant="dense"] {
    border: 1px solid
      var(--diff-view-border-soft, color-mix(in oklab, var(--border) 50%, transparent));
    border-radius: 2px;
  }

  [data-slot="diff-view"][data-variant="dense"] [data-slot="diff-view-rows"] {
    grid-template-columns:
      [num-l] minmax(3ch, max-content)
      [div-l] 1px
      [num-r] minmax(3ch, max-content)
      [div-r] 1px
      [marker] 1.25ch
      [code] 1fr;
  }
  /* Split-side rows render a single number column per pane, so dense mode
     uses a 4-cell track here (num + divider + marker + code) instead of the
     6-cell unified track above. */
  [data-slot="diff-view"][data-variant="dense"] [data-slot="diff-view-rows"][data-side] {
    grid-template-columns:
      [num] minmax(3ch, max-content)
      [div] 1px
      [marker] 1.25ch
      [code] 1fr;
  }
  [data-slot="diff-view"][data-variant="dense"]
    [data-slot="diff-view-rows"][data-line-numbers="false"] {
    grid-template-columns: [marker] 1.25ch [code] 1fr;
  }
  [data-slot="diff-view"][data-variant="dense"] .diff-num-divider {
    background: color-mix(in oklab, var(--diff-view-border, var(--border)) 40%, transparent);
  }
  [data-slot="diff-view"][data-variant="dense"] [data-row][data-state="added"] .diff-num-divider {
    background: color-mix(in oklab, var(--diff-color-add) 35%, transparent);
  }
  [data-slot="diff-view"][data-variant="dense"] [data-row][data-state="removed"] .diff-num-divider {
    background: color-mix(in oklab, var(--diff-color-remove) 35%, transparent);
  }
  [data-slot="diff-view"][data-variant="dense"] .diff-num {
    padding-inline: 0.75ch;
  }

  /* ============================================================
     Variant: viewfinder — four bracketed corners, family consistency
     with dialog viewfinder language.
     ============================================================ */
  [data-slot="diff-view"][data-variant="viewfinder"] {
    --viewfinder-size: 14px;
    --viewfinder-weight: 1.5px;
    --viewfinder-color: var(--diff-view-fg, var(--foreground));
    --viewfinder-offset: 0px;
    position: relative;
    background: var(--diff-view-bg, var(--background));
    padding: 14px 16px 10px;
  }

  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > span {
    position: absolute;
    pointer-events: none;
    width: var(--viewfinder-size);
    height: var(--viewfinder-size);
    border: 0 solid var(--viewfinder-color);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-tl {
    top: var(--viewfinder-offset);
    left: var(--viewfinder-offset);
    border-top-width: var(--viewfinder-weight);
    border-left-width: var(--viewfinder-weight);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-tr {
    top: var(--viewfinder-offset);
    right: var(--viewfinder-offset);
    border-top-width: var(--viewfinder-weight);
    border-right-width: var(--viewfinder-weight);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-bl {
    bottom: var(--viewfinder-offset);
    left: var(--viewfinder-offset);
    border-bottom-width: var(--viewfinder-weight);
    border-left-width: var(--viewfinder-weight);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-br {
    bottom: var(--viewfinder-offset);
    right: var(--viewfinder-offset);
    border-bottom-width: var(--viewfinder-weight);
    border-right-width: var(--viewfinder-weight);
  }

  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-caption"] {
    display: flex;
    align-items: baseline;
    gap: 8px;
    padding: 0 4px 10px;
    border-bottom: none;
    font-size: 12px;
    color: var(--diff-view-fg, var(--foreground));
  }

  /* ============================================================
     Variant: statusbar — top hairline + content + optional bottom
     consumer-filled status bar slot.
     ============================================================ */
  [data-slot="diff-view"][data-variant="statusbar"] {
    background: transparent;
  }

  [data-slot="diff-view"][data-variant="statusbar"] [data-slot="diff-view-caption"] {
    border-bottom: 1px solid
      color-mix(in oklab, var(--diff-view-border, var(--border)) 40%, transparent);
    padding: 4px 12px;
  }

  [data-slot="diff-view"][data-variant="statusbar"] [data-slot="diff-view-statusbar"] {
    border-top: 1px solid
      color-mix(in oklab, var(--diff-view-border, var(--border)) 30%, transparent);
    background: color-mix(in oklab, var(--diff-view-fg, var(--foreground)) 6%, transparent);
    padding: 3px 12px;
    font-size: 11px;
    color: var(--diff-view-muted, var(--muted-foreground));
  }

  /* ============================================================
     A11y / motion fallbacks.
     ============================================================ */
  @media (prefers-reduced-motion: reduce) {
    [data-slot="diff-view"][data-variant="bare"] {
      transition: none;
    }
  }

  @media (forced-colors: active) {
    [data-slot="diff-view"][data-variant="hairline"],
    [data-slot="diff-view"][data-variant="dense"] {
      border-color: CanvasText;
    }
    [data-slot="diff-view"][data-variant="bare"] {
      border-left-color: CanvasText;
    }
    [data-slot="diff-view-corners"] > span {
      border-color: CanvasText;
    }
    [data-row][data-state="added"] {
      background: Canvas;
      border-inline-start: 2px solid Mark;
    }
    [data-row][data-state="removed"] {
      background: Canvas;
      border-inline-start: 2px solid LinkText;
    }
    [data-slot="diff-view-rows"]:focus-visible {
      outline-color: Highlight;
    }
  }
}

/*
 * CommandPalette primitive styles. Two orthogonal axes drive visual chrome
 * via data-attribute selectors on [data-slot="command-palette-content"]:
 *   [data-frame] = border | viewfinder | terminal | card | none
 *   [data-density] = compact | comfortable | dense
 *
 * Density controls a CSS-variable surface read by every inner slot:
 *   --command-palette-row-h, --command-palette-row-px, --command-palette-row-py,
 *   --command-palette-input-py, --command-palette-input-px,
 *   --command-palette-list-p,
 *   --command-palette-heading-size, --command-palette-prefix-size, --command-palette-text-size
 *
 * Tone tokens (item left bar + icon tint) read from semantic theme tokens.
 */
@layer components {
  /*
   * Default component-token values are consumed via var() fallback (not declared
   * on the slot) so an ancestor-scoped override reaches them. Defaults: --command-palette-bg →
   * var(--background); --command-palette-fg → var(--foreground); --command-palette-border → var(--border);
   * --command-palette-border-soft → color-mix(in oklab, var(--border) 60%, transparent);
   * --command-palette-muted → var(--muted-foreground); --command-palette-prefix-content → ">";
   * --command-palette-tone-nav → var(--info); --command-palette-tone-action → var(--success);
   * --command-palette-tone-settings → var(--warning); --command-palette-tone-destructive → var(--error);
   * --command-palette-tone-ai → var(--accent). The [data-frame="terminal"] prefix override below still wins.
   */
  [data-slot="command-palette-content"] {
    position: relative;
    background: var(--command-palette-bg, var(--background));
    color: var(--command-palette-fg, var(--foreground));
  }

  /* Density: compact (default) */
  [data-slot="command-palette-content"][data-density="compact"] {
    --command-palette-row-h: 32px;
    --command-palette-row-px: 12px;
    --command-palette-row-py: 8px;
    --command-palette-input-py: 12px;
    --command-palette-input-px: 16px;
    --command-palette-list-p: 6px;
    --command-palette-heading-size: 12px;
    --command-palette-prefix-size: 14px;
    --command-palette-text-size: 14px;
  }

  /* Density: comfortable */
  [data-slot="command-palette-content"][data-density="comfortable"] {
    --command-palette-row-h: 40px;
    --command-palette-row-px: 12px;
    --command-palette-row-py: 10px;
    --command-palette-input-py: 16px;
    --command-palette-input-px: 20px;
    --command-palette-list-p: 8px;
    --command-palette-heading-size: 12px;
    --command-palette-prefix-size: 15px;
    --command-palette-text-size: 14px;
  }

  /* Density: dense */
  [data-slot="command-palette-content"][data-density="dense"] {
    --command-palette-row-h: 24px;
    --command-palette-row-px: 8px;
    --command-palette-row-py: 3px;
    --command-palette-input-py: 8px;
    --command-palette-input-px: 12px;
    --command-palette-list-p: 4px;
    --command-palette-heading-size: 11px;
    --command-palette-prefix-size: 13px;
    --command-palette-text-size: 13px;
  }

  /* Frame: border (default) — single 1px hairline. */
  [data-slot="command-palette-content"][data-frame="border"] {
    border: 1px solid var(--command-palette-border, var(--border));
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  /* Frame: viewfinder — no border, four corner brackets. */
  [data-slot="command-palette-content"][data-frame="viewfinder"] {
    border: 0;
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"]::after,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    border: 0 solid var(--command-palette-fg, var(--foreground));
    pointer-events: none;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before {
    top: -1px;
    left: -1px;
    border-top-width: 2px;
    border-left-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::after {
    top: -1px;
    right: -1px;
    border-top-width: 2px;
    border-right-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before {
    bottom: -1px;
    left: -1px;
    border-bottom-width: 2px;
    border-left-width: 2px;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    bottom: -1px;
    right: -1px;
    border-bottom-width: 2px;
    border-right-width: 2px;
  }

  /* Frame: terminal — top + bottom 2px rules, no side borders. */
  [data-slot="command-palette-content"][data-frame="terminal"] {
    border: 0;
    border-top: 2px solid var(--command-palette-fg, var(--foreground));
    border-bottom: 2px solid var(--command-palette-fg, var(--foreground));
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
    --command-palette-prefix-content: "$";
  }

  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-input-prefix"] {
    color: var(--command-palette-fg, var(--foreground));
    font-weight: 700;
  }

  /* Frame: card — Linear-ish rounded shell with a subtle gradient surface. */
  [data-slot="command-palette-content"][data-frame="card"] {
    border: 1px solid var(--command-palette-border, var(--border));
    border-radius: 8px;
    background: linear-gradient(
      140deg,
      color-mix(
          in oklab,
          var(--command-palette-fg, var(--foreground)) 6%,
          var(--command-palette-bg, var(--background))
        )
        0%,
      var(--command-palette-bg, var(--background)) 100%
    );
    box-shadow: 0 30px 80px oklch(0% 0 0 / 0.7);
    overflow: hidden;
  }

  /* Frame: none — bare. */
  [data-slot="command-palette-content"][data-frame="none"] {
    border: 0;
    box-shadow: 0 20px 60px oklch(0% 0 0 / 0.6);
  }

  /* Input row */
  [data-slot="command-palette-input"] {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: var(--command-palette-input-py) var(--command-palette-input-px);
    border-bottom: 1px solid
      var(--command-palette-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
  }

  [data-slot="command-palette-input-prefix"] {
    color: var(--command-palette-muted, var(--muted-foreground));
    font-size: var(--command-palette-prefix-size);
    user-select: none;
    flex-shrink: 0;
  }

  [data-slot="command-palette-input-prefix"][data-default]::before {
    content: var(--command-palette-prefix-content, ">");
  }

  [data-slot="command-palette-input-suffix"] {
    display: inline-flex;
    align-items: center;
    flex-shrink: 0;
  }

  /* List */
  [data-slot="command-palette-list"] {
    padding: var(--command-palette-list-p);
  }

  /* Group */
  [data-slot="command-palette-group-heading"] {
    padding: 8px 10px 4px;
    font-size: var(--command-palette-heading-size);
    font-weight: 500;
    color: var(--command-palette-muted, var(--muted-foreground));
  }

  /* Frame-scoped heading typography. Mirrors V2/V3 in the variants preview. */
  [data-slot="command-palette-content"][data-frame="viewfinder"]
    [data-slot="command-palette-group-heading"] {
    text-transform: uppercase;
    letter-spacing: 0.06em;
    font-size: 11px;
  }

  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-group-heading"] {
    padding: 6px var(--command-palette-input-px) 2px;
    font-weight: 400;
  }

  /* Item */
  [data-slot="command-palette-item"] {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: var(--command-palette-row-py) var(--command-palette-row-px);
    min-height: var(--command-palette-row-h);
    font-size: var(--command-palette-text-size);
    color: var(--command-palette-fg, var(--foreground));
    cursor: pointer;
    user-select: none;
    position: relative;
  }

  [data-slot="command-palette-item"][aria-disabled="true"] {
    opacity: 0.5;
    cursor: not-allowed;
  }

  [data-slot="command-palette-item"][aria-selected="true"] {
    background: color-mix(in oklab, var(--command-palette-fg, var(--foreground)) 7%, transparent);
    color: var(--command-palette-fg, var(--foreground));
  }

  /* Viewfinder frame replaces the selection tint with a 2px left accent bar
     (matches the dialog viewfinder language). Use ::after so it doesn't
     collide with the tone bar at [data-tone]:not([data-tone="neutral"])::before. */
  [data-slot="command-palette-content"][data-frame="viewfinder"]
    [data-slot="command-palette-item"][aria-selected="true"] {
    background: transparent;
    font-weight: 500;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]
    [data-slot="command-palette-item"][aria-selected="true"]::after {
    content: "";
    position: absolute;
    left: 0;
    top: 4px;
    bottom: 4px;
    width: 2px;
    background: var(--command-palette-fg, var(--foreground));
    pointer-events: none;
  }

  /* Terminal frame inverts selection (white-on-black). */
  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-item"][aria-selected="true"] {
    background: var(--command-palette-fg, var(--foreground));
    color: var(--command-palette-bg, var(--background));
    font-weight: 500;
  }

  /* Card frame: rows float inside the list padding with a rounded selection. */
  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-item"] {
    margin: 0 var(--command-palette-list-p);
    border-radius: 6px;
  }

  [data-slot="command-palette-content"][data-frame="card"]
    [data-slot="command-palette-item"][aria-selected="true"] {
    background: color-mix(in oklab, var(--command-palette-fg, var(--foreground)) 8%, transparent);
  }

  [data-slot="command-palette-item-icon"] {
    display: inline-flex;
    align-items: center;
    color: var(--command-palette-muted, var(--muted-foreground));
    flex-shrink: 0;
  }

  [data-slot="command-palette-item-label"] {
    flex: 1 1 auto;
    min-width: 0;
  }

  [data-slot="command-palette-item-shortcut"] {
    color: var(--command-palette-muted, var(--muted-foreground));
    font-size: 11px;
    flex-shrink: 0;
  }

  /* Tones: 2px left bar + icon tint. Label color inherits to preserve readability. */
  [data-slot="command-palette-item"][data-tone]:not([data-tone="neutral"])::before {
    content: "";
    position: absolute;
    left: 4px;
    top: 8px;
    bottom: 8px;
    width: 2px;
  }

  [data-slot="command-palette-item"][data-tone="nav"]::before {
    background: var(--command-palette-tone-nav, var(--info));
  }
  [data-slot="command-palette-item"][data-tone="action"]::before {
    background: var(--command-palette-tone-action, var(--success));
  }
  [data-slot="command-palette-item"][data-tone="settings"]::before {
    background: var(--command-palette-tone-settings, var(--warning));
  }
  [data-slot="command-palette-item"][data-tone="destructive"]::before {
    background: var(--command-palette-tone-destructive, var(--error));
  }
  [data-slot="command-palette-item"][data-tone="ai"]::before {
    background: var(--command-palette-tone-ai, var(--accent));
  }

  /* Hide the tone bar on disabled rows; the muted row body already signals state. */
  [data-slot="command-palette-item"][aria-disabled="true"]::before {
    display: none;
  }

  [data-slot="command-palette-item"][data-tone="nav"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-nav, var(--info));
  }
  [data-slot="command-palette-item"][data-tone="action"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-action, var(--success));
  }
  [data-slot="command-palette-item"][data-tone="settings"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-settings, var(--warning));
  }
  [data-slot="command-palette-item"][data-tone="destructive"]
    [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-destructive, var(--error));
  }
  [data-slot="command-palette-item"][data-tone="ai"] [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-tone-ai, var(--accent));
  }

  /* Under the terminal frame's inverted selection (bg: --command-palette-fg, color: --command-palette-bg)
     tones lose contrast: in the dark-mode minimal theme several tone tokens
     resolve to the same color as --foreground (e.g. --success → --base-success
     → #e5e5e5 = white), which would render the 2px bar and icon invisible
     against the white selection background. Re-tint both to --command-palette-bg so they
     remain visible without re-coloring the label. */
  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-item"][aria-selected="true"]
    [data-slot="command-palette-item-icon"] {
    color: var(--command-palette-bg, var(--background));
  }

  [data-slot="command-palette-content"][data-frame="terminal"]
    [data-slot="command-palette-item"][aria-selected="true"][data-tone]:not(
      [data-tone="neutral"]
    )::before {
    background: var(--command-palette-bg, var(--background));
  }

  /* Match highlight */
  [data-slot="command-palette-item-match"] {
    color: var(--command-palette-fg, var(--foreground));
    background: transparent;
    font-weight: 600;
    text-decoration: underline;
    text-underline-offset: 2px;
    text-decoration-thickness: 1px;
  }

  /* Empty state */
  [data-slot="command-palette-empty"] {
    padding: 24px 12px;
    text-align: center;
    font-size: var(--command-palette-text-size);
    color: var(--command-palette-muted, var(--muted-foreground));
  }

  /* Footer */
  [data-slot="command-palette-footer"] {
    display: flex;
    align-items: center;
    gap: 16px;
    flex-wrap: wrap;
    padding: 8px 12px;
    border-top: 1px solid
      var(--command-palette-border-soft, color-mix(in oklab, var(--border) 60%, transparent));
    font-size: 11px;
    color: var(--command-palette-muted, var(--muted-foreground));
    user-select: none;
  }

  [data-slot="command-palette-content"][data-frame="card"] [data-slot="command-palette-footer"] {
    background: color-mix(in oklab, black 25%, transparent);
    border-top: 1px solid
      color-mix(in oklab, var(--command-palette-fg, var(--foreground)) 8%, transparent);
  }
}

@media (forced-colors: active) {
  [data-slot="command-palette-content"][data-frame="border"],
  [data-slot="command-palette-content"][data-frame="terminal"],
  [data-slot="command-palette-content"][data-frame="card"] {
    border-color: CanvasText;
  }

  [data-slot="command-palette-content"][data-frame="viewfinder"]::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"]::after,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::before,
  [data-slot="command-palette-content"][data-frame="viewfinder"] > .cp-corners::after {
    border-color: CanvasText;
  }
}

/*
 * Sidebar collapsible-section animation contract.
 *
 * Matches the floating-surface motion language used by Select / Popover
 * (60ms enter / 40ms exit, linear, opacity fade) and extends it with a
 * height tween so accordion sections animate cleanly without the snap
 * caused by toggling `display: none` (the `hidden` attribute cannot
 * transition).
 *
 * Mechanics:
 *   - The collapsible panel is a CSS grid whose `grid-template-rows`
 *     animates between `0fr` (closed) and `1fr` (open). Its single child
 *     uses `min-height: 0; overflow: hidden` so the grid can squeeze the
 *     row to zero. This is the bullet-proof modern accordion technique —
 *     no JS height measurement, no `interpolate-size` / `@starting-style`
 *     gating, works in every evergreen browser.
 *   - Opacity fades alongside height using the same duration tokens as
 *     `.ui-floating-panel` so the visual cadence matches Select.
 *
 * Reduced motion:
 *   - `motion-reduce` (`prefers-reduced-motion: reduce`) zeroes the
 *     transitions so the panel snaps. The element is always in the DOM,
 *     so SR users tabbing through closed sections must still skip the
 *     items — handled in JSX via `inert` + `aria-hidden`.
 */

[data-slot="sidebar-section-content"] {
  display: grid;
  grid-template-rows: 1fr;
  transition:
    grid-template-rows var(--ui-content-enter-duration, 60ms) linear,
    opacity var(--ui-content-enter-duration, 60ms) linear;
}

[data-slot="sidebar-section-content"][data-state="closed"] {
  grid-template-rows: 0fr;
  opacity: 0;
  transition:
    grid-template-rows var(--ui-content-exit-duration, 40ms) linear,
    opacity var(--ui-content-exit-duration, 40ms) linear;
}

[data-slot="sidebar-section-content"] > [data-slot="sidebar-section-content-inner"] {
  min-height: 0;
  overflow: hidden;
}

@media (prefers-reduced-motion: reduce) {
  [data-slot="sidebar-section-content"],
  [data-slot="sidebar-section-content"][data-state="closed"] {
    transition: none;
  }
}

/*
 * Tree-variant connectors: trunk (per-item vertical segment), tick
 * (horizontal branch at row middle), corner (the last item's trunk stops at
 * its tick, forming a └).
 *
 * The trunk needs contiguous rows (the tree item variant uses padding, not
 * gap) and CSS :last-child for the corner — tree items must be direct
 * siblings; a non-item element after the last item mislabels the corner.
 *
 * Geometry (assumes a collapsible tree section): the trunk descends from the
 * section title's fold chevron (px-2 gutter + half of the 12px chevron =
 * 14px); the 6px tick ends 4px before the item text at pl-6 (24px), which
 * lines up with that title text. A non-collapsible title has no chevron — its
 * text sits at 8px, so items indent past it.
 */
[data-slot="sidebar"][data-variant="tree"] [data-diffgazer-navigation-item]::before {
  content: "";
  position: absolute;
  left: 14px;
  top: 0;
  bottom: 0;
  border-left: 1px solid color-mix(in oklab, var(--border) 75%, transparent);
}

[data-slot="sidebar"][data-variant="tree"] [data-diffgazer-navigation-item]:last-child::before {
  bottom: 50%;
}

[data-slot="sidebar"][data-variant="tree"] [data-diffgazer-navigation-item]::after {
  content: "";
  position: absolute;
  left: 14px;
  top: 50%;
  width: 6px;
  border-top: 1px solid color-mix(in oklab, var(--border) 75%, transparent);
}

[data-slot="sidebar"][data-variant="tree"] [data-diffgazer-navigation-item][data-selected]::after {
  border-top-color: var(--foreground);
}

/* Rail mode hides labels, so connectors go too. */
[data-slot="sidebar"][data-state="rail"][data-variant="tree"]
  [data-diffgazer-navigation-item]::before,
[data-slot="sidebar"][data-state="rail"][data-variant="tree"]
  [data-diffgazer-navigation-item]::after {
  content: none;
}
